prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?choreo (COUNT(DISTINCT ?par) AS ?parallelGateways) WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?par a bboExt:ParallelGateway ;
       tai:belongsTo ?choreo .
}
GROUP BY ?model ?modelName ?created ?choreo
ORDER BY DESC(?parallelGateways) ?created
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created .
}
ORDER BY ?created
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName (COUNT(DISTINCT ?gw) AS ?gatewayCount) (SUM(IF(?isPar=1,1,0)) AS ?parallelGatewayCount) WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?gw a ?gwType ;
      tai:belongsTo ?choreo .

  FILTER(?gwType IN (bboExt:ParallelGateway, bboExt:ExclusiveGateway, bboExt:EventBasedGateway))
  BIND(IF(?gwType = bboExt:ParallelGateway, 1, 0) AS ?isPar)
}
GROUP BY ?model ?modelName
ORDER BY DESC(?parallelGatewayCount) ?modelName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?par ?parName WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName .

  ?par a bboExt:ParallelGateway .
  ?par tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .

  OPTIONAL { ?par bbo:name ?parName . }
}
LIMIT 25
